import React, { useState, useEffect } from "react";
import { useNavigate, Link } from "react-router-dom";
import { Image, Form} from 'react-bootstrap'
import MainLayout from "../../components/Layout";
import BASE_URL from "../../config";
import DatePicker from "react-datepicker";
import "react-datepicker/dist/react-datepicker.css";
import $ from 'jquery';
import * as bootstrap from "bootstrap";
import SummaryCard from "../../components/SummaryCard";

function Employee({ setModuleName }) {
   const [headNoRecord, setHeadNoRecord] = useState(false);
   const [searchText, setSearchText] = useState("");
   const [searchofficelevels, setSearchOfficeLevels] = useState([]);
   const [selectedsearchOfficeLevel, setSelectedSearchOfficeLevel] = useState("");
   const [searchofficeid, setSearchOfficeID] = useState([]);
   const [selectedSearchOfficeID, setSelectedSearchOfficeID] = useState("");
   const [religions, setReligion] = useState([]);
   const [selectedReligion, setSelectedReligion] = useState("");
   const [titles, setTitle] = useState([]);
   const [selectedTitle, setSelectedTitle] = useState("");
   const [designations, setDesignation] = useState([]);
   const [selectedDesignation, setSelectedDesignation] = useState("");
   const [states, setStates] = useState([]);
   const [selectedState, setSelectedState] = useState("");
   const [district, setDistrict] = useState([]);
   const [selectedDistrict, setSelectedDistrict] = useState("");
   const [officelevels, setOfficeLevels] = useState([]);
   const [selectedOfficeLevel, setSelectedOfficeLevel] = useState("");
   const [offices, setOffice] = useState([]);
   const [selectedOffice, setSelectedOffice] = useState("");
   const [errors, setErrors] = useState({});
   const [employees, setEmployees] = useState([]);

   const [employee, setEmployee] = useState({ emp_code: "",title_id:0, emp_name: "",emp_name_local:"",emp_father_name: "",emp_father_name_local:"",
   emp_mother_name: "",emp_mother_name_local:"",emp_spouse_name: "",emp_spouse_name_local:"",emp_photo: null,dob:null,gender:"",religion_id:0,state_id:0,
   district_id:0, address: "",mobile_no1: "", mobile_no2: "", email_id: "", office_id: "", joining_date:null,desig_id:0,emp_type:"",action: "S", status: "A",});
  
 const cards = [
  { title: "Total Employees",count:1,  bgColor: "#eff6ff", iconColor: "#1d4ed8", icon: "fa fa-user" },
  { title: "Headquarter",count:1,  bgColor: "#f0fdf4", iconColor: "#16a34a", icon: "fa fa-user" },
  { title: "Regional Offices",count:1,  bgColor: "#fffbeb", iconColor: "#d97706", icon: "fa fa-user" },
  { title: "District Offices",count:1,  bgColor: "#fef2f2", iconColor: "#dc2626", icon: "fa fa-user" },
  
];

   useEffect(() => {
      setModuleName("Employee Management");
      setHeadNoRecord(true);
      loadEmployeeList();
      loadStates();
      loadDesignation();
      loadNameTitle();
      loadReligion();
      loadOfficeLevels();
   }, []);

   const loadDesignation = async () => {
            try {
               const response = await fetch(`${BASE_URL}/user/get-designation`);
               const data = await response.json();
               setDesignation(data);
            } catch (err) {
               console.log(err);
            }
         };   
   const loadNameTitle = async () => {
            try {
               const response = await fetch(`${BASE_URL}/user/get-nametitle`);
               const data = await response.json();
               setTitle(data);
            } catch (err) {
               console.log(err);
            }
         };
   const loadReligion = async () => {
            try {
               const response = await fetch(`${BASE_URL}/user/get-religion`);
               const data = await response.json();
               setReligion(data);
            } catch (err) {
               console.log(err);
            }
         };
   const loadStates = async () => {
      try {
         const response = await fetch(`${BASE_URL}/user/get-state`);
         const data = await response.json();
         setStates(data);
      } catch (err) {
         console.log(err);
      }
   };
   const loadDistrict = async (StateID) => {
      try {
         const response = await fetch(`${BASE_URL}/user/get-district`,
            {
            method: "POST",
            headers: {
               "Content-Type": "application/json",
            },
            body: JSON.stringify({
               state_id: Number(StateID),
            }),
            }
         );
            const data = await response.json();
            setDistrict(data);
         } catch (err) {
            console.log(err);
         }
   };
   const loadOfficeLevels = async () => {
      try {
         const response = await fetch(`${BASE_URL}/user/get-officelevel`);
         const data = await response.json();
         setOfficeLevels(data);
      } catch (err) {
         console.log(err);
      }
   };
   const loadOffice = async (OfficeLevelID) => {
      try {
         const response = await fetch(`${BASE_URL}/user/get-dropdownoffice`,
            {
            method: "POST",
            headers: {
               "Content-Type": "application/json",
            },
            body: JSON.stringify({
               office_level_id: Number(OfficeLevelID),
            }),
            }
         );
         const data = await response.json();
         setOffice(data);
         setSearchOfficeID(data);
      } catch (err) {
         console.log(err);
      }
      };
   const loadEmployeeList = async (officeLevelID = "", officeID = "",searchtxt="") => {
      try {
         const response = await fetch(`${BASE_URL}/user/get-employeelist`,
            {
            method: "POST",
            headers: { "Content-Type": "application/json", },
            body: JSON.stringify({ office_level_id: officeLevelID ? Number(officeLevelID): 0, office_id: officeID || "",search_text: searchtxt||"",
            }),
            }
         );
         const data = await response.json();
         const employeeList = Array.isArray(data) ? data : [];
         
         setEmployees(employeeList);
         console.log(employeeList.length);
         if (employeeList.length === 0) {
            setHeadNoRecord(true);
         } else {
            setHeadNoRecord(false);
         }

      } catch (err) {
         console.log(err);
         setHeadNoRecord(true);
      }
   };

   const validateForm = () => {
      let tempErrors = {};

      // Office Name
      if (!employee.emp_code.trim()) {
         tempErrors.emp_code = "Employee code is required";
      }
      if (!employee.emp_name.trim()) {
         tempErrors.emp_name = "Employee name is required";
      }
      if (!employee.mobile_no1.trim()) {
      } else if (!/^[0-9]{10}$/.test(employee.mobile_no1)) {
         tempErrors.mobile_no1 = "Mobile number must be 10 digits";
      }
      if (!employee.mobile_no2.trim()) {
      } else if (!/^[0-9]{10}$/.test(employee.mobile_no2)) {
         tempErrors.mobile_no2 = "Mobile number 2 must be 10 digits";
      }
      if (!employee.email_id.trim()) {
      } else if (
         !/^[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}$/i.test(employee.email_id)
      ) {
         tempErrors.email_id = "Invalid email address";
      }

      setErrors(tempErrors);

      return Object.keys(tempErrors).length === 0;
   };

   const saveEmployee = async (e) => {
      e.preventDefault();
      if (!validateForm()) {
         return;
      }
      const employeeData = {
         ...employee,
         action: employee.action,
         status: "A",
      };


      try {
         const response = await fetch(`${BASE_URL}/user/addupdateemployee`,
            {
            method: "POST",
            credentials: "include",
            headers: {
               "Content-Type": "application/json",
            },
            body: JSON.stringify(employeeData),
            }
         );

         const data = await response.json();

         if (response.ok) {
            let message = "Employee Details Saved Successfully";

            if (employeeData.action === "U") {
            message = "Employee updated successfully";
            }

            if (employeeData.action === "R") {
            message = "Employee deleted successfully";
            }
            alert(message);
            loadEmployeeList();
            // Clear form
            setEmployee({emp_code: "",title_id:0, emp_name: "",emp_name_local:"",emp_father_name: "",emp_father_name_local:"", emp_mother_name: "",
            emp_mother_name_local:"",emp_spouse_name: "",emp_spouse_name_local:"",emp_photo: null,dob:null,gender:"",religion_id:0,state_id:0, district_id:0,
            address: "",mobile_no1: "", mobile_no2: "", email_id: "", office_level_id:0, office_id: "", joining_date: null,desig_id:0,emp_type:"",action: "S", status: "A",});

            setSelectedState("");
            setSelectedDesignation("");
            setSelectedReligion("");
            setSelectedTitle("");
            setDistrict([]);
            setSelectedOfficeLevel("");
            loadOffice(0)
            setSelectedOffice("");

         } else {
            alert(data.message || "Failed to save employee");
         }
      } catch (err) {
         console.log(err);
         alert("Error while saving employee");
      }
   };
   const searchOffice = () => {

  let filtered = [...employee];
  // Filter by office level
  if (selectedsearchOfficeLevel !== "") {
    filtered = filtered.filter(
      (item) =>
        String(item.office_level_id) ===
        String(selectedsearchOfficeLevel)
    );
  }
  // Filter by office id
  if (selectedSearchOfficeID !== "") {filtered = filtered.filter((item) => String(item.office_id) === String(selectedSearchOfficeID));
  }
  setEmployees(filtered);
};
const resetFilter = () => {
  setSelectedSearchOfficeLevel("");
  setSelectedSearchOfficeID("");
  setSearchOfficeID([]);
  loadEmployeeList("", "");
};

const handleEdit = (b) => {

  setEmployee({
      emp_id: b.emp_id,
      emp_code: b.emp_code,
      title_id:b.title_id,
      emp_name: b.emp_name,
      emp_name_local:b.emp_name_local,
      emp_father_name: b.emp_father_name,
      emp_father_name_local:b.emp_father_name_local,
      emp_mother_name: b.emp_mother_name,
      emp_mother_name_local:b.emp_mother_name_local,
      emp_spouse_name: b.emp_spouse_name,
      emp_spouse_name_local:b.emp_spouse_name_local,
      dob:b.dob,
      gender:b.gender,
      religion_id:b.religion_id,
      state_id:b.state_id,   
      district_id:b.district_id,
      address: b.address,
      mobile_no1: b.mobile_no1,
      mobile_no2: b.mobile_no2,
      email_id: b.email_id,
      office_level_id: b.office_level_id,
      office_id: b.office_id,
      joining_date:b.joining_date,
      desig_id:b.desig_id,
      emp_type:b.emp_type,
      action: "U",
      status: "A"
  });

  setSelectedOfficeLevel(b.office_level_id);
  loadOffice(b.office_level_id)
  setSelectedOffice(b.office_id);
  setSelectedState(b.state_id);
  loadDistrict(b.state_id);
  setSelectedDistrict(b.district_id);
  setSelectedDesignation(b.desig_id);
  setSelectedReligion(b.religion);
  setSelectedTitle(b.title_id);
};

const handleDelete = async (empID,action) => {
  let message = "";

  switch (action) {
    case "R":
      message = "Are you sure you want to delete?";
      break;

    case "A":
      message = "Are you sure you want to activate?";
      break;

    case "D":
      message = "Are you sure you want to deactivate?";
      break;

    default:
      message = "Are you sure?";
  }

  const confirmDelete = window.confirm(message);
  if (!confirmDelete) {
    return;
  }

  try {
    const deleteEmployee = {emp_id: empID,action: action, status: "D",
    };
    const response = await fetch(`${BASE_URL}/user/addupdateemployee`,
      {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        credentials:"include",
        body: JSON.stringify(deleteEmployee),
      }
    );

    const data = await response.json();
    if (response.ok) {
      if(action=="R")
      {
      alert("Office Deleted Successfully");
      }
      else if(action=="D")
      {
      alert("Office Deactivated Successfully");
      }
      else if(action=="A")
      {
      alert("Office Activated Successfully");
      }
      loadEmployeeList();
    } else {
      alert(data.message || "Update failed");
    }

  } catch (err) {
    console.log(err);
    alert("Error while updating office");
  }
};

